def iter_ledger(
    self, from_id: Optional[str] = None, to_id: Optional[str] = None
) -> Iterator[LedgerEntry]:
    with self.session() as s:
        rows = s.exec(
            select(StoredLedgerEntry).order_by(asc(StoredLedgerEntry.timestamp))
        ).all()
    started = from_id is None
    for r in rows:
        if not started:
